mapper.select:
SELECT
    SUM(amount) as total_amount
FROM t_bill
WHERE user_id = #{userId}
    AND time >= #{startTime}
    AND time <= #{endTime}
    AND deleted = 0
    AND type = #{type}

    AND family_id = #{familyId}

SELECT
    b.category_id AS categoryId,
    c.name AS categoryName,
    c.icon AS categoryIcon,
    SUM(b.amount) AS amount
FROM t_bill b
LEFT JOIN t_category c ON b.category_id = c.id
WHERE b.user_id = #{userId}
    AND b.time >= #{startTime}
    AND b.time <= #{endTime}
    AND b.deleted = 0
    AND b.type = #{type}
    AND b.category_id IS NOT NULL

    AND b.family_id = #{familyId}

GROUP BY b.category_id, c.name, c.icon
ORDER BY amount DESC

SELECT
DATE_FORMAT(time, '%Y-%m-%d') AS date,
SUM(IF(type = 'expense', amount, 0)) AS expense,
SUM(IF(type = 'income', amount, 0)) AS income
FROM t_bill
WHERE user_id = #{userId}
AND time >= #{startTime}
AND time <= #{endTime}
AND deleted = 0

      AND family_id = #{familyId}

GROUP BY DATE(time)
ORDER BY DATE(time)
